#include <vector>

class Solution {
public:
    int numIslands(std::vector<std::vector<char>>& grid) {
        if (grid.empty() || grid[0].empty()) {
            return 0;
        }

        int numberOfRows = grid.size();
        int numberOfColumns = grid[0].size();
        int islandCount = 0;

        for (int currentRow = 0; currentRow < numberOfRows; ++currentRow) {
            for (int currentCol = 0; currentCol < numberOfColumns; ++currentCol) {
                // If we find land that hasn't been visited yet, it's a new island.
                if (grid[currentRow][currentCol] == '1') {
                    islandCount++;
                    // Explore all connected land to mark it as visited.
                    exploreIsland(grid, currentRow, currentCol);
                }
            }
        }

        return islandCount;
    }

private:
    void exploreIsland(std::vector<std::vector<char>>& grid, int currentRow, int currentCol) {
        int numberOfRows = grid.size();
        int numberOfColumns = grid[0].size();

        // Base cases for recursion: out of bounds or not land.
        if (currentRow < 0 || currentRow >= numberOfRows || currentCol < 0 || currentCol >= numberOfColumns || grid[currentRow][currentCol] != '1') {
            return;
        }

        // Mark the current land as visited to avoid recounting.
        grid[currentRow][currentCol] = '0';

        // Recursively explore adjacent land cells.
        exploreIsland(grid, currentRow + 1, currentCol);
        exploreIsland(grid, currentRow - 1, currentCol);
        exploreIsland(grid, currentRow, currentCol + 1);
        exploreIsland(grid, currentRow, currentCol - 1);
    }
};

