fn num_islands(grid: &mut Vec<Vec<char>>) -> i32 {
    let mut island_counter: i32 = 0;
    let number_of_rows = grid.len();
    if number_of_rows == 0 {
        return 0;
    }
    let number_of_columns = grid[0].len();

    for row_index in 0..number_of_rows {
        for column_index in 0..number_of_columns {
            // When we find land ('1'), it signifies the start of a new island.
            if grid[row_index][column_index] == '1' {
                island_counter += 1;
                // Explore and sink all connected land pieces of this new island.
                sink_connected_land(grid, row_index as i32, column_index as i32);
            }
        }
    }

    // By sinking connected land, each island is counted exactly once.
    island_counter
}

fn sink_connected_land(grid: &mut Vec<Vec<char>>, current_row: i32, current_column: i32) {
    let number_of_rows = grid.len() as i32;
    let number_of_columns = grid[0].len() as i32;

    // Base cases for recursion: out of bounds or already water/visited.
    if current_row < 0 || current_row >= number_of_rows || current_column < 0 || current_column >= number_of_columns || grid[current_row as usize][current_column as usize] == '0' {
        return;
    }

    // Mark the current land piece as visited by turning it into water ('0').
    grid[current_row as usize][current_column as usize] = '0';

    // Recursively sink adjacent land pieces (up, down, left, right).
    sink_connected_land(grid, current_row + 1, current_column);
    sink_connected_land(grid, current_row - 1, current_column);
    sink_connected_land(grid, current_row, current_column + 1);
    sink_connected_land(grid, current_row, current_column - 1);
}

