class Solution {
    fun numIslands(grid: Array<CharArray>): Int {
        var numberOfIslands: Int = 0
        val numberOfRows: Int = grid.size
        if (numberOfRows == 0) {
            return 0
        }
        val numberOfColumns: Int = grid[0].size

        for (rowIndex in 0 until numberOfRows) {
            for (columnIndex in 0 until numberOfColumns) {
                // If we find land ('1'), it signifies the start of a new island.
                if (grid[rowIndex][columnIndex] == '1') {
                    numberOfIslands++
                    // Explore and 'sink' all connected land to avoid recounting.
                    exploreAndSinkIsland(grid, rowIndex, columnIndex)
                }
            }
        }
        return numberOfIslands
    }

    private fun exploreAndSinkIsland(grid: Array<CharArray>, rowIndex: Int, columnIndex: Int) {
        val numberOfRows: Int = grid.size
        val numberOfColumns: Int = grid[0].size

        // Base cases for recursion: out of bounds or water.
        if (rowIndex < 0 || rowIndex >= numberOfRows || columnIndex < 0 || columnIndex >= numberOfColumns || grid[rowIndex][columnIndex] == '0') {
            return
        }

        // Mark the current land as visited by changing it to water ('0').
        grid[rowIndex][columnIndex] = '0'

        // Recursively explore adjacent land cells (up, down, left, right).
        exploreAndSinkIsland(grid, rowIndex + 1, columnIndex)
        exploreAndSinkIsland(grid, rowIndex - 1, columnIndex)
        exploreAndSinkIsland(grid, rowIndex, columnIndex + 1)
        exploreAndSinkIsland(grid, rowIndex, columnIndex - 1)
    }
}
